"""Validated environment for the provisioner agent."""

from __future__ import annotations

import os
from dataclasses import dataclass
from urllib.parse import urlparse

PROVISIONER_REQUIRED_ENV_VARS: tuple[str, ...] = ("REBASE_API_BASE_URL",)


@dataclass(frozen=True, slots=True)
class ProvisionerSettings:
    rebase_api_base_url: str


def _require_env(name: str) -> str:
    value = os.environ.get(name, "").strip()
    if not value:
        raise ValueError(f"Missing required environment variable: {name}")
    return value


def load_provisioner_settings() -> ProvisionerSettings:
    """Load provisioner settings; fail fast when the rebase API base URL is missing."""
    base_url = _require_env("REBASE_API_BASE_URL")
    parsed = urlparse(base_url)
    if parsed.scheme not in {"http", "https"} or not parsed.netloc:
        raise ValueError("REBASE_API_BASE_URL must be an http(s) URL with a host")
    return ProvisionerSettings(rebase_api_base_url=base_url.rstrip("/"))

"""Progress queue and AGUI tile event builders for live provisioning updates."""

from __future__ import annotations

import asyncio
import json
import uuid
from dataclasses import dataclass, field
from typing import Any

from agno.models.response import ToolExecution
from agno.run.agent import RunOutputEvent, ToolCallCompletedEvent, ToolCallStartedEvent

from agents.provisioner.constants import PROVISION_LOG_MAX
from agents.provisioner.contracts import ProvisionPipelineCardProps, ProvisionPipelineStep
from agents.provisioner.render_tools import (
    RENDER_PROVISION_PIPELINE_CARD,
    render_provision_pipeline_card,
)

RenderTileEvent = RunOutputEvent


@dataclass
class PipelineProgressState:
    steps: list[ProvisionPipelineStep] = field(
        default_factory=lambda: [
            {"id": "dev_infra", "status": "pending"},
            {"id": "terminal_bootstrap", "status": "pending"},
        ]
    )
    log_tail: list[str] = field(default_factory=list)
    last_log: str | None = None
    current_stage: str | None = None

    def append_log(self, message: str) -> None:
        self.last_log = message
        self.log_tail.append(message)
        if len(self.log_tail) > PROVISION_LOG_MAX:
            self.log_tail = self.log_tail[-PROVISION_LOG_MAX:]

    def props(self) -> ProvisionPipelineCardProps:
        props: ProvisionPipelineCardProps = {
            "steps": self.steps,
            "logTail": list(self.log_tail),
        }
        if self.last_log is not None:
            props["lastLog"] = self.last_log
        if self.current_stage is not None:
            props["currentStage"] = self.current_stage  # type: ignore[typeddict-item]
        return props


class ProgressQueue:
    """In-memory queue of pending render tile events for one agent run."""

    def __init__(self) -> None:
        self._queue: asyncio.Queue[RenderTileEvent] = asyncio.Queue()

    async def put_tile_events(self, *, run_meta: dict[str, Any], props: ProvisionPipelineCardProps) -> None:
        for event in build_pipeline_tile_events(run_meta=run_meta, props=props):
            await self._queue.put(event)

    async def get(self) -> RenderTileEvent:
        return await self._queue.get()

    def empty(self) -> bool:
        return self._queue.empty()


def build_pipeline_tile_events(
    *,
    run_meta: dict[str, Any],
    props: ProvisionPipelineCardProps,
) -> list[RenderTileEvent]:
    tool_call_id = str(uuid.uuid4())
    result = render_provision_pipeline_card.entrypoint(**props)  # type: ignore[misc]
    tool = ToolExecution(
        tool_call_id=tool_call_id,
        tool_name=RENDER_PROVISION_PIPELINE_CARD,
        tool_args=dict(props),
        result=json.dumps(result),
    )
    return [
        ToolCallStartedEvent(
            tool=tool,
            agent_id=run_meta.get("agent_id"),
            agent_name=run_meta.get("agent_name"),
            run_id=run_meta["run_id"],
            session_id=run_meta["session_id"],
        ),
        ToolCallCompletedEvent(
            tool=tool,
            content=result,
            agent_id=run_meta.get("agent_id"),
            agent_name=run_meta.get("agent_name"),
            run_id=run_meta["run_id"],
            session_id=run_meta["session_id"],
        ),
    ]


def progress_queue_from_dependencies(dependencies: dict[str, Any] | None) -> ProgressQueue:
    if not dependencies:
        raise RuntimeError("Provisioner progress queue is missing from run dependencies")
    queue = dependencies.get("provisioner_progress_queue")
    if not isinstance(queue, ProgressQueue):
        raise RuntimeError("Provisioner progress queue is missing from run dependencies")
    return queue


def run_meta_from_context(run_context: Any) -> dict[str, Any]:
    return {
        "run_id": run_context.run_id,
        "session_id": run_context.session_id,
        "agent_id": getattr(run_context, "agent_id", None),
        "agent_name": getattr(run_context, "agent_name", None),
    }

"""Merge live provision pipeline tile events with the agent AGUI stream."""

from __future__ import annotations

import asyncio
from collections.abc import AsyncIterator
from typing import Any, cast

from agno.agent import Agent
from agno.run.agent import RunCompletedEvent, RunEvent, RunOutputEvent

from agents.provisioner.constants import PROGRESS_QUEUE_DEP_KEY
from agents.provisioner.progress import ProgressQueue


async def merge_progress_stream(
    response_stream: AsyncIterator[RunOutputEvent],
    queue: ProgressQueue,
) -> AsyncIterator[RunOutputEvent]:
    """Interleave progress tile events with model events until the run completes."""
    agent_iter = response_stream.__aiter__()
    agent_exhausted = False
    completion: RunCompletedEvent | None = None

    while True:
        while not queue.empty():
            yield await queue.get()

        if agent_exhausted:
            if queue.empty():
                break
            yield await queue.get()
            continue

        progress_task = asyncio.create_task(queue.get())
        agent_task = asyncio.create_task(agent_iter.__anext__())
        done, pending = await asyncio.wait(
            {progress_task, agent_task},
            return_when=asyncio.FIRST_COMPLETED,
        )
        for task in pending:
            task.cancel()

        if progress_task in done:
            try:
                yield progress_task.result()
            except Exception:
                pass

        if agent_task in done:
            try:
                chunk = agent_task.result()
            except StopAsyncIteration:
                agent_exhausted = True
            else:
                if chunk.event == RunEvent.run_completed.value:
                    completion = cast(RunCompletedEvent, chunk)
                else:
                    yield chunk

    while not queue.empty():
        yield await queue.get()

    if completion is not None:
        yield completion


def wrap_provisioner_arun(agent: Agent) -> None:
    """Wrap arun to inject a per-run progress queue and merge tile updates when streaming."""
    base_arun = agent.arun

    def arun(*args: Any, **kwargs: Any) -> Any:
        stream = kwargs.get("stream", False)
        stream_events = kwargs.get("stream_events", False)
        if stream and stream_events:
            queue = ProgressQueue()
            deps = dict(kwargs.get("dependencies") or {})
            deps[PROGRESS_QUEUE_DEP_KEY] = queue
            kwargs["dependencies"] = deps
            result = base_arun(*args, **kwargs)
            return merge_progress_stream(result, queue)
        return base_arun(*args, **kwargs)

    agent.arun = arun  # type: ignore[method-assign, assignment]

